1	/**
2	 * Theme controller — spec §23.
3	 *
4	 * - Default theme is `light`. Activate dark by setting `data-theme="dark"`
5	 *   on `<html>` (and a back-compat `.dark` class).
6	 * - Component code never branches on theme. It only reads tokens.
7	 * - Source of truth (in priority order):
8	 *     1. `#theme=…` URL hash (shareable view)
9	 *     2. `localStorage["bim.theme"]`
10	 *     3. `prefers-color-scheme` media query
11	 * - Toggle action persists to all three.
12	 */
13	
14	export const THEME_VALUES = ['light', 'dark'] as const;
15	export type Theme = (typeof THEME_VALUES)[number];
16	
17	const STORAGE_KEY = 'bim.theme';
18	const HASH_KEY = 'theme';
19	
20	function isTheme(value: string | null | undefined): value is Theme {
21	  return value === 'light' || value === 'dark';
22	}
23	
24	function parseHashTheme(hash: string): Theme | null {
25	  const raw = hash.startsWith('#') ? hash.slice(1) : hash;
26	  if (!raw) return null;
27	  const params = new URLSearchParams(raw);
28	  const candidate = params.get(HASH_KEY);
29	  return isTheme(candidate) ? candidate : null;
30	}
31	
32	function writeHashTheme(theme: Theme): void {
33	  if (typeof window === 'undefined') return;
34	  try {
35	    const raw = window.location.hash.startsWith('#')
36	      ? window.location.hash.slice(1)
37	      : window.location.hash;
38	    const params = new URLSearchParams(raw);
39	    params.set(HASH_KEY, theme);
40	    const next = `#${params.toString()}`;
41	    if (window.location.hash !== next) {
42	      window.history.replaceState(null, '', next);
43	    }
44	  } catch {
45	    /* noop */
46	  }
47	}
48	
49	function readStorageTheme(): Theme | null {
50	  if (typeof localStorage === 'undefined') return null;
51	  try {
52	    const value = localStorage.getItem(STORAGE_KEY);
53	    return isTheme(value) ? value : null;
54	  } catch {
55	    return null;
56	  }
57	}
58	
59	function writeStorageTheme(theme: Theme): void {
60	  try {
61	    localStorage.setItem(STORAGE_KEY, theme);
62	  } catch {
63	    /* noop */
64	  }
65	}
66	
67	function readSystemPreference(): Theme {
68	  if (typeof window === 'undefined' || typeof window.matchMedia !== 'function') {
69	    return 'light';
70	  }
71	  try {
72	    return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
73	  } catch {
74	    return 'light';
75	  }
76	}
77	
